const now = new Date();
const digestDate = now.toLocaleDateString('en-CA', { timeZone: 'Europe/London' });
return [{ json: { digestDate, runAt: now.toISOString() } }];

const digestDate = $('Get Digest Date').first().json.digestDate;
const msgs = $input.all();

if (!msgs || msgs.length === 0) {
  return [{ json: { skip: true, inbox: 'support@syntharra.com', label: 'Support', digestDate, count: 0 } }];
}

const emails = msgs.map(item => {
  const msg = item.json;
  const headers = msg.payload?.headers || [];
  const h = (name) => (headers.find(x => x.name.toLowerCase() === name.toLowerCase()) || {}).value || '';
  return {
    id: msg.id,
    threadId: msg.threadId,
    from: h('From'),
    subject: h('Subject') || '(no subject)',
    date: h('Date'),
    snippet: (msg.snippet || '').substring(0, 600),
    labels: (msg.labelIds || []).join(',')
  };
}).filter(e => e.id);

return [{ json: { skip: false, inbox: 'support@syntharra.com', label: 'Support', digestDate, emails, count: emails.length } }];

