const digestDate = $('Get Digest Date').first().json.digestDate;
const classifyData = $('Classify — Support').first().json;

// If inbox was empty, nothing to do
if (classifyData.skip) {
  return [{ json: { saved: 0, inbox: 'support@syntharra.com', label: 'Support', digestDate } }];
}

// Parse Groq response
let classified = [];
try {
  const body = $input.item.json.body || $input.item.json;
  const content = body?.choices?.[0]?.message?.content || body?.message?.content || '';
  const parsed = typeof content === 'string' ? JSON.parse(content) : content;
  classified = parsed?.emails || [];
} catch(e) {
  console.error('Groq parse error for Support:', e.message);
  return [{ json: { saved: 0, error: e.message, inbox: 'support@syntharra.com', label: 'Support', digestDate } }];
}

if (!classified.length) {
  return [{ json: { saved: 0, inbox: 'support@syntharra.com', label: 'Support', digestDate } }];
}

// ── Delete today's existing records for this inbox (idempotent re-runs) ──
const SUPABASE_URL = 'https://hgheyqwnrcvwtgngqdnq.supabase.co';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY || '';

await fetch(`${SUPABASE_URL}/rest/v1/email_digest?digest_date=eq.${digestDate}&inbox_address=eq.support@syntharra.com`, {
  method: 'DELETE',
  headers: { apikey: SUPABASE_KEY, Authorization: 'Bearer ' + SUPABASE_KEY }
});

// ── Insert classified emails ──
const records = classified
  .filter(e => e && e.id && ['high','medium'].includes(e.importance))
  .map(e => {
    let receivedAt = null;
    try {
      if (e.date) receivedAt = new Date(e.date).toISOString();
    } catch(e) {}

    return {
      digest_date:     digestDate,
      inbox_address:   'support@syntharra.com',
      inbox_label:     'Support',
      email_id:        e.id,
      thread_id:       e.threadId || null,
      from_address:    (e.from || '').substring(0, 500),
      subject:         (e.subject || '(no subject)').substring(0, 500),
      snippet:         (e.snippet || '').substring(0, 500),
      ai_summary:      (e.summary || '').substring(0, 500),
      importance:      e.importance,
      category:        e.category || 'general',
      action_required: !!e.action_required,
      flag:            ['urgent','opportunity','hire'].includes(e.flag) ? e.flag : null,
      received_at:     receivedAt
    };
  });

if (!records.length) {
  return [{ json: { saved: 0, inbox: 'support@syntharra.com', label: 'Support', digestDate } }];
}

const insertResp = await fetch(`${SUPABASE_URL}/rest/v1/email_digest`, {
  method: 'POST',
  headers: {
    apikey: SUPABASE_KEY,
    Authorization: 'Bearer ' + SUPABASE_KEY,
    'Content-Type': 'application/json',
    Prefer: 'return=minimal'
  },
  body: JSON.stringify(records)
});

if (!insertResp.ok) {
  const err = await insertResp.text();
  console.error('Supabase insert error for Support:', err);
  return [{ json: { saved: 0, error: err, inbox: 'support@syntharra.com', label: 'Support', digestDate } }];
}

return [{ json: { saved: records.length, inbox: 'support@syntharra.com', label: 'Support', digestDate, records } }];

